<template>
  <div class="product-details mt-16" :key="singalProduct.id">
    <v-container fluid>
      <v-row>
        <v-col cols="12" md="7">
          <img
            :src="tab ? tab : singalProduct.thumbnail"
            alt=""
            class="w-100"
            height="500"
            v-if="!loading"
          />
          <v-skeleton-loader
            type="image,image , image"
            v-if="loading"
          ></v-skeleton-loader>
          <v-tabs center-active height="220" v-model="tab" class="mt-10">
            <v-tab
              v-for="(img, i) in singalProduct.images"
              :key="i"
              class="mx-10"
              :value="img"
            >
              <img :src="img" alt="" width="100" height="200" />
            </v-tab>
          </v-tabs>
        </v-col>
        <v-col cols="12" md="5" class="pt-0 pl-6 mt-8 mt-md-0">
          <v-skeleton-loader
            type="article,article , article"
            v-if="loading"
          ></v-skeleton-loader>
          <v-card elevation="0" v-if="!loading">
            <v-card-title class="px-0 text-h6 font-weight-bold"
              >{{ singalProduct.title }} Sample -
              {{ singalProduct.category }} For Sale</v-card-title
            >
            <div class="rating-parent d-flex align-center ga-1">
              <v-rating
                v-model="singalProduct.rating"
                half-increments
                readonly
                color="yellow-darken-2"
                size="x-small"
                density="compact"
              ></v-rating>
              <v-chip variant="text" color="rgb(96,96,96)"
                >Stock:{{ singalProduct.stock }}</v-chip
              >
            </div>
            <v-card-text class="px-0" style="color: #606060; font-size: 14px">{{
              singalProduct.description
            }}</v-card-text>
            <v-card-text
              class="px-0 pt-0"
              style="color: #606060; font-size: 14px"
              >Brand:{{ singalProduct.brand }}</v-card-text
            >
            <v-card-text
              class="px-0 pt-0"
              style="color: #606060; font-size: 14px"
              >Availability:{{
                singalProduct.stock > 0 ? "In Stock" : "Out Of Stock"
              }}</v-card-text
            >
            <v-card-text
              class="px-0 pt-0"
              style="color: #606060; font-size: 14px"
            >
              <del>${{ singalProduct.price }}</del> From
              <v-chip variant="text" color="error" class="font-weight-bold">
                ${{
                  Math.ceil(
                    singalProduct.price -
                      singalProduct.price *
                        (singalProduct.discountPercentage / 100)
                  )
                }}
              </v-chip>
            </v-card-text>
            <v-card-text class="px-0 pt-0"> Quantity </v-card-text>
            <div
              class="counte px-1"
              style="
                border-radius: 30px;
                border: 1px solid rgb(201, 201, 201);
                width: fit-content;
              "
            >
              <v-icon size="22" @click="quantity > 1 ? quantity-- : false"
                >mdi-minus</v-icon
              >
              <input
                type="number"
                style="
                  border: none;
                  outline: none;
                  text-align: center;
                  width: 60px;
                  font-size: 13px;
                "
                class="py-3"
                min="1"
                v-model="quantity"
              />
              <v-icon size="22" @click="quantity++">mdi-plus</v-icon>
            </div>
            <v-card-text class="pl-0">
              Subtotal: ${{
                Math.ceil(
                  singalProduct.price -
                    singalProduct.price *
                      (singalProduct.discountPercentage / 100)
                ) * quantity
              }}
            </v-card-text>
            <v-card-actions class="mt-7 w-100 px-0">
              <v-btn
                variant="outlined"
                style="text-transform: none; background-color: rgb(34, 34, 34)"
                class="w-75"
                density="compact"
                height="50"
                rounded="xl"
                color="#fff"
                :loading="btnLoading"
                @click="addToCart(singalProduct)"
                >Add To Cart</v-btn
              >
            </v-card-actions>
          </v-card>
        </v-col>
      </v-row>
    </v-container>
  </div>
</template>
<script setup>
import { ref, computed, onBeforeMount, inject } from "vue";
import { productsModule } from "@/stores/Products";
import { useRoute } from "vue-router";
import { VSkeletonLoader } from "vuetify/lib/components";

import { cartStore } from "@/stores/cart";
const cart = cartStore();
// * Variables DownBelow
const loading = ref(false);
const store = productsModule();
const tab = ref(null);
const quantity = ref(1);
const emitter = inject("emitter");
const btnLoading = ref(false);
// * Functions downBelow
const singalProduct = computed(() => store.singalProduct);
const route = useRoute();
onBeforeMount(async () => {
  loading.value = true;
  await store.getSingleProduct(route.query.productId);
  loading.value = false;
});

const addToCart = (item) => {
  item.quantity = quantity.value;
  btnLoading.value = true;
  setTimeout(() => {
    btnLoading.value = false;
    cart.addItems(item);
    emitter.emit("openCart");
    emitter.emit("showMsg", item.title);
  }, 1000);
};
</script>
